// Direct integer DAC -> Hz, with clamping for out-of-range inputs.
inline double v4Hz(int dac) noexcept
{
    if (dac < 0) return kV4Hz[0];
    if (dac >= static_cast<int>(kV4HzSize)) return kV4Hz[kV4HzSize - 1];
    return kV4Hz[dac];
}

